from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a written work into a single fluent sentence.
    """
    if not triples:
        return ""

    parts = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Simple template mapping for common predicates
        if p == "author":
            phrase = f"{s} was authored by {o}"
        elif p == "isbnNumber":
            phrase = f"{s} has ISBN {o}"
        elif p == "followedBy":
            phrase = f"{s} is followed by {o}"
        elif p == "precededBy":
            phrase = f"{s} is preceded by {o}"
        elif p == "language":
            phrase = f"{s} is written in {o}"
        elif p == "mediaType":
            phrase = f"{s} is a {o} publication"
        elif p == "numberOfPages":
            phrase = f"{s} contains {o} pages"
        elif p == "country":
            phrase = f"{s} originates from {o}"
        elif p == "publisher":
            phrase = f"{s} was published by {o}"
        elif p == "releaseDate":
            phrase = f"{s} was released on {o}"
        elif p == "birthDate":
            phrase = f"{s} was born on {o}"
        elif p == "genre" or p == "literaryGenre":
            phrase = f"{s} belongs to the {o} genre"
        else:
            # Generic fallback
            phrase = f"{s} has {p} {o}"

        parts.append(phrase)

    # Combine parts into a single coherent sentence
    if len(parts) == 1:
        return parts[0] + "."
    else:
        return ", ".join(parts[:-1]) + ", and " + parts[-1] + "."

# EVOLVE-BLOCK-END

